parameters.jsCode:
const items = $input.all();
const item = items[0].json;

let lignes = item.lignes;
if (typeof lignes === 'string') {
  try { lignes = JSON.parse(lignes); } catch(e) { lignes = []; }
}
if (!Array.isArray(lignes)) lignes = [lignes];

let montant_ht = 0;
const parsed = lignes.map((l, i) => {
  const qty = Number(l.quantite) || 1;
  const prix = Number(l.prix_unitaire_ht) || 0;
  const total = Math.round(qty * prix * 100) / 100;
  montant_ht += total;
  return {
    designation: l.designation || l.description || '',
    quantite: qty,
    prix_unitaire_ht: prix,
    total_ht: total,
    ordre: i + 1
  };
});

montant_ht = Math.round(montant_ht * 100) / 100;
const tva = Math.round(montant_ht * 20) / 100;
const montant_ttc = Math.round((montant_ht + tva) * 100) / 100;

return [{
  json: {
    tenant_id: item.tenant_id,
    client_final_id: item.client_final_id,
    montant_ht,
    tva,
    montant_ttc,
    lignes_json: JSON.stringify(parsed)
  }
}];
